167	/// Read one shell word starting at `*i`, advancing `*i` past it and `*line`
168	/// over any embedded newlines. Quoted segments and `${...}` parameter
169	/// expansions are consumed as part of the word; an embedded `$(` command
170	/// substitution STOPS the word so the caller's lexer scans the substituted
171	/// command at its own command position.
172	pub(crate) fn zrbtdru_read_word(chars: &[char], i: &mut usize, line: &mut usize) -> String {
173	    let n = chars.len();
174	    let mut word = String::new();
175	    while *i < n {
176	        let c = chars[*i];
177	        match c {
178	            ' ' | '\t' | '\r' | '\n' => break,
179	            ';' | '|' | '&' | '<' | '>' | '(' | ')' | '`' | '#' => break,
180	            '\'' => {
181	                word.push(c);
182	                *i += 1;
183	                while *i < n && chars[*i] != '\'' {
184	                    if chars[*i] == '\n' {
185	                        *line += 1;
186	                    }
187	                    word.push(chars[*i]);
188	                    *i += 1;
189	                }
190	                if *i < n {
191	                    word.push(chars[*i]);
192	                    *i += 1;
193	                }
194	            }
195	            '"' => {
196	                word.push(c);
197	                *i += 1;
198	                while *i < n && chars[*i] != '"' {
199	                    if chars[*i] == '\\' && *i + 1 < n {
200	                        word.push(chars[*i]);
201	                        word.push(chars[*i + 1]);
202	                        *i += 2;
203	                        continue;
204	                    }
205	                    if chars[*i] == '\n' {
206	                        *line += 1;
207	                    }
208	                    word.push(chars[*i]);
209	                    *i += 1;
210	                }
211	                if *i < n {
212	                    word.push(chars[*i]);
213	                    *i += 1;
214	                }
215	            }
216	            '$' if *i + 1 < n && chars[*i + 1] == '(' => break,
217	            '$' if *i + 1 < n && chars[*i + 1] == '{' => {
218	                word.push('$');
219	                *i += 1;
220	                let mut depth = 0usize;
221	                while *i < n {
222	                    let d = chars[*i];
223	                    if d == '\n' {
224	                        *line += 1;
225	                    }
226	                    word.push(d);
227	                    *i += 1;
228	                    if d == '{' {
229	                        depth += 1;
230	                    } else if d == '}' {
231	                        depth -= 1;
232	                        if depth == 0 {
233	                            break;
234	                        }
235	                    }
236	                }
237	            }
238	            _ => {
239	                word.push(c);
240	                *i += 1;
241	            }
242	        }
243	    }
244	    word
245	}
