247	/// Classify a word as transparent or value-introducing when it sits in command
248	/// position. `Some(true)` — a keyword whose successor is itself a command
249	/// (`if`, `then`, `while`, …). `Some(false)` — a keyword whose successor is a
250	/// value, not a command (`for`, `case`, `in`, …). `None` — not a keyword.
251	pub(crate) fn zrbtdru_keyword_kind(word: &str) -> Option<bool> {
252	    match word {
253	        "if" | "elif" | "while" | "until" | "then" | "else" | "do" | "!"
254	        | "time" | "fi" | "done" | "esac" => Some(true),
255	        "for" | "select" | "case" | "in" | "function" => Some(false),
256	        _ => None,
257	    }
258	}
