260	/// True when `word` is a `NAME=`, `NAME+=`, or `NAME[idx]=` assignment prefix —
261	/// a command may still follow on the same line (`FOO=bar cmd`), so command
262	/// position is preserved across it.
263	pub(crate) fn zrbtdru_is_assignment(word: &str) -> bool {
264	    let bytes = word.as_bytes();
265	    if bytes.is_empty() {
266	        return false;
267	    }
268	    let first = bytes[0] as char;
269	    if !(first.is_ascii_alphabetic() || first == '_') {
270	        return false;
271	    }
272	    let mut k = 1;
273	    while k < bytes.len() {
274	        let ch = bytes[k] as char;
275	        if ch == '=' {
276	            return true;
277	        }
278	        if ch == '+' && k + 1 < bytes.len() && bytes[k + 1] == b'=' {
279	            return true;
280	        }
281	        if ch == '[' {
282	            return word.contains("]=");
283	        }
284	        if !(ch.is_ascii_alphanumeric() || ch == '_') {
285	            return false;
286	        }
287	        k += 1;
288	    }
289	    false
290	}
