292	/// Advance `*i` past a balanced run of parentheses, tracking newlines in
293	/// `*line`. `depth` is the count of opening parens already consumed by the
294	/// caller; scanning ends when it returns to zero. Quoted segments are skipped
295	/// so parens inside strings do not affect the balance — covering array literals
296	/// `NAME=( … )` and nested arithmetic `$(( ( … ) ))`.
297	pub(crate) fn zrbtdru_skip_balanced_parens(chars: &[char], i: &mut usize, line: &mut usize, mut depth: usize) {
298	    let n = chars.len();
299	    while *i < n && depth > 0 {
300	        match chars[*i] {
301	            '(' => depth += 1,
302	            ')' => depth -= 1,
303	            '\n' => *line += 1,
304	            '\'' => {
305	                *i += 1;
306	                while *i < n && chars[*i] != '\'' {
307	                    if chars[*i] == '\n' {
308	                        *line += 1;
309	                    }
310	                    *i += 1;
311	                }
312	            }
313	            '"' => {
314	                *i += 1;
315	                while *i < n && chars[*i] != '"' {
316	                    if chars[*i] == '\\' && *i + 1 < n {
317	                        *i += 2;
318	                        continue;
319	                    }
320	                    if chars[*i] == '\n' {
321	                        *line += 1;
322	                    }
323	                    *i += 1;
324	                }
325	            }
326	            _ => {}
327	        }
328	        *i += 1;
329	    }
330	}
