332	/// Extract every command-position token from a bash source string, paired with
333	/// its 1-based line number. A token is in command position at the start of the
334	/// script and after any command separator (`;`, `|`, `&`, `&&`, `||`, newline,
335	/// `(`, `$(`, `` ` ``, an open brace group) and after a transparent keyword.
336	/// Assignments, redirections, `[[ ]]` test contents, comments, here-doc bodies,
337	/// and arithmetic `(( ))` / `$(( ))` are excluded.
338	pub(crate) fn zrbtdru_command_words(src: &str) -> Vec<(usize, String)> {
339	    let chars: Vec<char> = src.chars().collect();
340	    let n = chars.len();
341	    let mut out: Vec<(usize, String)> = Vec::new();
342	    let mut i = 0usize;
343	    let mut line = 1usize;
344	    let mut cmd_pos = true;
345	    let mut paren_depth = 0usize;
346	    let mut in_dbracket = false;
347	    let mut pending_heredoc: Option<String> = None;
348	    // case…esac nesting. Each frame tracks the position within a `case`:
349	    // 0 = subject (between `case` and `in`), 1 = pattern (suppress recording;
350	    // `|` is alternation, not a pipe), 2 = branch body (record commands).
351	    let mut case_stack: Vec<u8> = Vec::new();
352	
353	    while i < n {
354	        let c = chars[i];
355	
356	        if c == '\n' {
357	            i += 1;
358	            line += 1;
359	            cmd_pos = true;
360	            if let Some(delim) = pending_heredoc.take() {
361	                loop {
362	                    let start = i;
363	                    while i < n && chars[i] != '\n' {
364	                        i += 1;
365	                    }
366	                    let body: String = chars[start..i].iter().collect();
367	                    let had_nl = i < n;
368	                    if had_nl {
369	                        i += 1;
370	                        line += 1;
371	                    }
372	                    if body.trim() == delim {
373	                        break;
374	                    }
375	                    if !had_nl {
376	                        break;
377	                    }
378	                }
379	            }
380	            continue;
381	        }
382	        if c == ' ' || c == '\t' || c == '\r' {
383	            i += 1;
384	            continue;
385	        }
386	        if c == '\\' && i + 1 < n && chars[i + 1] == '\n' {
387	            i += 2;
388	            line += 1;
389	            continue;
390	        }
391	        if c == '#' {
392	            while i < n && chars[i] != '\n' {
393	                i += 1;
394	            }
395	            continue;
396	        }
397	        if c == ';' {
398	            i += 1;
399	            if i < n && chars[i] == ';' {
400	                i += 1;
401	                // `;;` ends a case branch — the next token opens a new pattern.
402	                if let Some(top) = case_stack.last_mut() {
403	                    *top = 1;
404	                }
405	                cmd_pos = false;
406	                continue;
407	            }
408	            if !in_dbracket {
409	                cmd_pos = true;
410	            }
411	            continue;
412	        }
413	        if c == '|' {
414	            i += 1;
415	            if i < n && chars[i] == '|' {
416	                i += 1;
417	            }
418	            // Within a case pattern `|` is alternation, not a pipe.
419	            if case_stack.last() == Some(&1) {
420	                continue;
421	            }
422	            if !in_dbracket {
423	                cmd_pos = true;
424	            }
425	            continue;
426	        }
427	        if c == '&' {
428	            if i + 1 < n && chars[i + 1] == '>' {
429	                i += 2;
430	                if i < n && chars[i] == '>' {
431	                    i += 1;
432	                }
433	                cmd_pos = false;
434	                continue;
435	            }
436	            i += 1;
437	            if i < n && chars[i] == '&' {
438	                i += 1;
439	            }
440	            if !in_dbracket {
441	                cmd_pos = true;
442	            }
443	            continue;
444	        }
445	        if c == '<' {
446	            if i + 1 < n && chars[i + 1] == '<' {
447	                if i + 2 < n && chars[i + 2] == '<' {
448	                    i += 3;
449	                    cmd_pos = false;
450	                    continue;
451	                }
452	                i += 2;
453	                if i < n && chars[i] == '-' {
454	                    i += 1;
455	                }
456	                while i < n && (chars[i] == ' ' || chars[i] == '\t') {
457	                    i += 1;
458	                }
459	                let mut delim = String::new();
460	                let quote = if i < n && (chars[i] == '\'' || chars[i] == '"') {
461	                    let q = chars[i];
462	                    i += 1;
463	                    Some(q)
464	                } else {
465	                    None
466	                };
467	                while i < n {
468	                    let d = chars[i];
469	                    match quote {
470	                        Some(qc) => {
471	                            if d == qc {
472	                                i += 1;
473	                                break;
474	                            }
475	                            delim.push(d);
476	                            i += 1;
477	                        }
478	                        None => {
479	                            if d == ' ' || d == '\t' || d == '\n' || d == ';'
480	                                || d == '&' || d == '|' || d == '<' || d == '>'
481	                                || d == '(' || d == ')'
482	                            {
483	                                break;
484	                            }
485	                            if d == '\\' {
486	                                i += 1;
487	                                continue;
488	                            }
489	                            delim.push(d);
490	                            i += 1;
491	                        }
492	                    }
493	                }
494	                if !delim.is_empty() {
495	                    pending_heredoc = Some(delim);
496	                }
497	                cmd_pos = false;
498	                continue;
499	            }
500	            i += 1;
501	            if i < n && chars[i] == '&' {
502	                i += 1;
503	            }
504	            cmd_pos = false;
505	            continue;
506	        }
507	        if c == '>' {
508	            i += 1;
509	            if i < n && (chars[i] == '>' || chars[i] == '&') {
510	                i += 1;
511	            }
512	            cmd_pos = false;
513	            continue;
514	        }
515	        if c == '(' {
516	            if i + 1 < n && chars[i + 1] == '(' {
517	                // Arithmetic `(( … ))` — not a command list.
518	                i += 2;
519	                zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 2);
520	                cmd_pos = false;
521	                continue;
522	            }
523	            i += 1;
524	            paren_depth += 1;
525	            cmd_pos = true;
526	            continue;
527	        }
528	        if c == ')' {
529	            i += 1;
530	            if paren_depth > 0 {
531	                paren_depth -= 1;
532	                cmd_pos = false;
533	            } else if case_stack.last() == Some(&1) {
534	                // Pattern terminator — the branch body's command list follows.
535	                if let Some(top) = case_stack.last_mut() {
536	                    *top = 2;
537	                }
538	                cmd_pos = true;
539	            } else {
540	                cmd_pos = true;
541	            }
542	            continue;
543	        }
544	        if c == '`' {
545	            i += 1;
546	            cmd_pos = true;
547	            continue;
548	        }
549	        if c == '$' {
550	            if i + 1 < n && chars[i + 1] == '(' {
551	                if i + 2 < n && chars[i + 2] == '(' {
552	                    // Arithmetic substitution `$(( … ))` — not a command.
553	                    i += 3;
554	                    zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 2);
555	                    cmd_pos = false;
556	                    continue;
557	                }
558	                i += 2;
559	                paren_depth += 1;
560	                cmd_pos = true;
561	                continue;
562	            }
563	            let _ = zrbtdru_read_word(&chars, &mut i, &mut line);
564	            cmd_pos = false;
565	            continue;
566	        }
567	        if c == '{' {
568	            if i + 1 < n && (chars[i + 1] == ' ' || chars[i + 1] == '\t' || chars[i + 1] == '\n') {
569	                i += 1;
570	                cmd_pos = true;
571	                continue;
572	            }
573	            let _ = zrbtdru_read_word(&chars, &mut i, &mut line);
574	            cmd_pos = false;
575	            continue;
576	        }
577	        if c == '}' {
578	            i += 1;
579	            continue;
580	        }
581	
582	        let word_line = line;
583	        let word = zrbtdru_read_word(&chars, &mut i, &mut line);
584	        if word.is_empty() {
585	            i += 1;
586	            continue;
587	        }
588	        if word == "[[" {
589	            if cmd_pos {
590	                in_dbracket = true;
591	            }
592	            cmd_pos = false;
593	            continue;
594	        }
595	        if word == "]]" {
596	            in_dbracket = false;
597	            cmd_pos = false;
598	            continue;
599	        }
600	        if in_dbracket {
601	            continue;
602	        }
603	        // case…esac structure — tracked regardless of command position so that
604	        // branch patterns (which sit at command position) are not mistaken for
605	        // commands.
606	        if word == "case" {
607	            case_stack.push(0);
608	            cmd_pos = false;
609	            continue;
610	        }
611	        if word == "esac" {
612	            case_stack.pop();
613	            cmd_pos = false;
614	            continue;
615	        }
616	        if word == "in" && case_stack.last() == Some(&0) {
617	            if let Some(top) = case_stack.last_mut() {
618	                *top = 1;
619	            }
620	            cmd_pos = false;
621	            continue;
622	        }
623	        if case_stack.last() == Some(&1) {
624	            // Matching a case pattern — suppress; the pattern is not a command.
625	            cmd_pos = false;
626	            continue;
627	        }
628	        if !cmd_pos {
629	            continue;
630	        }
631	        if zrbtdru_is_assignment(&word) {
632	            // `NAME=( … )` array literal — the elements are data, not commands.
633	            let mut j = i;
634	            while j < n && (chars[j] == ' ' || chars[j] == '\t') {
635	                j += 1;
636	            }
637	            if j < n && chars[j] == '(' {
638	                i = j + 1;
639	                zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 1);
640	            }
641	            continue;
642	        }
643	        match zrbtdru_keyword_kind(&word) {
644	            Some(true) => continue,
645	            Some(false) => {
646	                cmd_pos = false;
647	                continue;
648	            }
649	            None => {}
650	        }
651	        out.push((word_line, word));
652	        cmd_pos = false;
653	    }
654	    out
655	}
