657	// ── Function collection and classification ──────────────────
658	
659	/// Harvest locally-defined function names from one source into `out`. Matches
660	/// both `name() {` and `function name` forms.
661	pub(crate) fn zrbtdru_collect_functions(src: &str, out: &mut BTreeSet<String>) {
662	    for raw in src.lines() {
663	        let trimmed = raw.trim_start();
664	        let rest = if let Some(after) = trimmed.strip_prefix("function ") {
665	            after.trim_start()
666	        } else {
667	            trimmed
668	        };
669	        let mut name = String::new();
670	        for ch in rest.chars() {
671	            if ch.is_ascii_alphanumeric() || ch == '_' || ch == '-' {
672	                name.push(ch);
673	            } else {
674	                break;
675	            }
676	        }
677	        if name.is_empty() {
678	            continue;
679	        }
680	        let after_name = rest[name.len()..].trim_start();
681	        if after_name.starts_with("()") || trimmed.starts_with("function ") {
682	            out.insert(name);
683	        }
684	    }
685	}
