687	/// Classify a command-position token. Returns `Some(detail)` when it violates
688	/// the domain's discipline, `None` when it is permitted. Dynamic tokens
689	/// (containing an expansion or quote) cannot be statically named and are
690	/// skipped.
691	pub(crate) fn zrbtdru_classify(
692	    command: &str,
693	    locals: &BTreeSet<String>,
694	    domain: zrbtdru_Domain,
695	) -> Option<String> {
696	    if command.is_empty() {
697	        return None;
698	    }
699	    if command.contains('$')
700	        || command.contains('`')
701	        || command.contains('"')
702	        || command.contains('\'')
703	    {
704	        return None;
705	    }
706	    let base = command.rsplit('/').next().unwrap_or(command);
707	    if ZRBTDRU_BUILTINS.contains(&base) {
708	        return None;
709	    }
710	    if locals.contains(command) || locals.contains(base) {
711	        return None;
712	    }
713	    if ZRBTDRU_POSIX_FLOOR.contains(&base) {
714	        return None;
715	    }
716	    if ZRBTDRU_DECLARED_DEPS.contains(&base) {
717	        return None;
718	    }
719	    match domain {
720	        zrbtdru_Domain::Kit => {
721	            for ev in ZRBTDRU_EVICTIONS {
722	                if ev.command == base {
723	                    return Some(format!("evicted command — use {}", ev.replacement));
724	                }
725	            }
726	            Some("unknown command — not in POSIX floor or RBS0 declared dependencies".to_string())
727	        }
728	        zrbtdru_Domain::Gcb => {
729	            if ZRBTDRU_GCB_EXTRA.contains(&base) {
730	                return None;
731	            }
732	            for ev in ZRBTDRU_EVICTIONS {
733	                if ev.command == base {
734	                    return None;
735	                }
736	            }
737	            Some("unknown command — not in the GCB allowlist".to_string())
738	        }
739	    }
740	}
