742	// ── Corpus walk and scan ────────────────────────────────────
743	
744	/// Recursively collect every `*.sh` file under `dir` into `out`.
745	fn zrbtdru_walk_sh(dir: &Path, out: &mut Vec<PathBuf>) {
746	    let entries = match std::fs::read_dir(dir) {
747	        Ok(e) => e,
748	        Err(_) => return,
749	    };
750	    for entry in entries.flatten() {
751	        let path = entry.path();
752	        if path.is_dir() {
753	            let abandoned = path
754	                .file_name()
755	                .and_then(|s| s.to_str())
756	                .map(|s| s.starts_with(ZRBTDRU_ABANDONED_DIR_PREFIX))
757	                .unwrap_or(false);
758	            if abandoned {
759	                continue;
760	            }
761	            zrbtdru_walk_sh(&path, out);
762	        } else if path.extension().and_then(|e| e.to_str()) == Some(ZRBTDRU_SH_EXT) {
763	            out.push(path);
764	        }
765	    }
766	}
767	
768	/// True when `path` lies under a Google Cloud Build job directory (any path
769	/// component beginning with the rbgj prefix).
770	fn zrbtdru_is_gcb(path: &Path) -> bool {
771	    path.components().any(|comp| {
772	        comp.as_os_str()
773	            .to_str()
774	            .map(|s| s.starts_with(ZRBTDRU_GCB_DIR_PREFIX))
775	            .unwrap_or(false)
776	    })
777	}
