779	/// Walk the corpus, collect functions across all of it, then scan the files
780	/// belonging to `domain`, returning every finding sorted by file and line.
781	fn zrbtdru_scan_domain(tools: &Path, domain: zrbtdru_Domain) -> Result<Vec<zrbtdru_Finding>, String> {
782	    let mut files: Vec<PathBuf> = Vec::new();
783	    zrbtdru_walk_sh(tools, &mut files);
784	    files.sort();
785	
786	    let mut sources: Vec<(PathBuf, String)> = Vec::with_capacity(files.len());
787	    for f in &files {
788	        let src = std::fs::read_to_string(f)
789	            .map_err(|e| format!("read {} failed: {}", f.display(), e))?;
790	        sources.push((f.clone(), src));
791	    }
792	
793	    let mut locals: BTreeSet<String> = BTreeSet::new();
794	    for (_, src) in &sources {
795	        zrbtdru_collect_functions(src, &mut locals);
796	    }
797	
798	    let root = tools.parent().unwrap_or(tools);
799	    let mut findings: Vec<zrbtdru_Finding> = Vec::new();
800	    for (path, src) in &sources {
801	        let is_gcb = zrbtdru_is_gcb(path);
802	        let in_domain = match domain {
803	            zrbtdru_Domain::Kit => !is_gcb,
804	            zrbtdru_Domain::Gcb => is_gcb,
805	        };
806	        if !in_domain {
807	            continue;
808	        }
809	        let rel = path.strip_prefix(root).unwrap_or(path).display().to_string();
810	        for (line, command) in zrbtdru_command_words(src) {
811	            if let Some(detail) = zrbtdru_classify(&command, &locals, domain) {
812	                findings.push(zrbtdru_Finding {
813	                    file: rel.clone(),
814	                    line,
815	                    command,
816	                    detail,
817	                });
818	            }
819	        }
820	    }
821	    Ok(findings)
822	}
