824	/// Render findings as a stable one-per-line report.
825	fn zrbtdru_render(findings: &[zrbtdru_Finding]) -> String {
826	    let mut report = String::new();
827	    for f in findings {
828	        report.push_str(&format!("{}:{}: {} — {}\n", f.file, f.line, f.command, f.detail));
829	    }
830	    report
831	}
