833	/// Drive one domain's scan, persist a findings trace into the case dir, and
834	/// fail the verdict when any violation remains.
835	fn zrbtdru_run_domain(dir: &Path, domain: zrbtdru_Domain, label: &str) -> rbtdre_Verdict {
836	    let root = match std::env::current_dir() {
837	        Ok(r) => r,
838	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
839	    };
840	    let tools = root.join(ZRBTDRU_TOOLS_SUBDIR);
841	    let findings = match zrbtdru_scan_domain(&tools, domain) {
842	        Ok(f) => f,
843	        Err(e) => return rbtdre_Verdict::Fail(e),
844	    };
845	    let report = zrbtdru_render(&findings);
846	    let _ = std::fs::write(dir.join(format!("cupel-{}-findings.txt", label)), &report);
847	
848	    if findings.is_empty() {
849	        rbtdre_Verdict::Pass
850	    } else {
851	        rbtdre_Verdict::Fail(format!(
852	            "{} BCG command-discipline violation(s) in {}-bash:\n{}",
853	            findings.len(),
854	            label,
855	            report
856	        ))
857	    }
858	}
